#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int count = 0;
        for (int a = 1; a < N; a++) {
            for (int b = a + 1; b <= N; b++) {
                if ((a * b) % (a + b) == 0) {
                    count++;
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

